import {
  successResponse,
  errorResponse,
  fromNeverthrowError,
  outputAndExit,
} from '@/cli/output';

import { safeParseResponse } from '@/shared/neverthrow/fetch';
import { executeFetch } from '@/operations/fetch';
import { cliFetchRequestSchema } from '@/shared/request/schemas/cli';
import { getWalletOrExit } from '../lib/get-wallet-or-exit';

import type z from 'zod';
import type { Command } from '@/types';

const SURFACE = 'cli:fetch';

export const fetchCommand: Command<
  z.input<typeof cliFetchRequestSchema>
> = async input => {
  const requestInput = cliFetchRequestSchema.safeParse(input);
  if (!requestInput.success) {
    return outputAndExit(
      errorResponse({
        code: 'INVALID_INPUT',
        message: requestInput.error.message,
        surface: SURFACE,
        cause: 'validation',
      }),
      input
    );
  }
  const wallets = await getWalletOrExit(input);

  const fetchResult = await executeFetch(requestInput.data, {
    surface: SURFACE,
    wallets,
    flags: input,
    params: input,
  });

  if (fetchResult.isErr()) {
    return outputAndExit(fromNeverthrowError(fetchResult), input);
  }

  const { response, paymentInfo } = fetchResult.value;

  if (!response.ok) {
    const parseResult = await safeParseResponse(SURFACE, response);
    return outputAndExit(
      errorResponse({
        code: 'HTTP_ERROR',
        message: response.statusText,
        surface: SURFACE,
        cause: 'http',
        details: parseResult.match(
          data => ({
            statusCode: response.status,
            type: data.type,
            body:
              data.type === 'json' || data.type === 'text'
                ? data.data
                : undefined,
          }),
          () => ({ statusCode: response.status })
        ),
      }),
      input
    );
  }

  const parseResponseResult = await safeParseResponse(SURFACE, response);
  if (parseResponseResult.isErr()) {
    return outputAndExit(fromNeverthrowError(parseResponseResult), input);
  }

  const parsedResponse = parseResponseResult.value;

  const data =
    parsedResponse.type === 'json' || parsedResponse.type === 'text'
      ? parsedResponse.data
      : { type: parsedResponse.type };

  outputAndExit(successResponse(data, paymentInfo), input);
};
